PsgVolEnv_0D:   db 00h, PsgVolEnvCtl_Sustain   ; sTone_0D (S3K VolEnv_0C)
PsgVolEnv_0E:   db 02h, PsgVolEnvCtl_Rest   ; sTone_0E (S3K VolEnv_0D)
